import{O as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.DGewWfie.js";import{t as r}from"./chunks/plugin-vue_export-helper.BDNMzG2s.js";var i=JSON.parse(`{"title":"技術能力","description":"","frontmatter":{},"headers":[],"relativePath":"skills.md","filePath":"skills.md","lastUpdated":1781254545000}`),a={name:`skills.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="技術能力" tabindex="-1">技術能力 <a class="header-anchor" href="#技術能力" aria-label="Permalink to “技術能力”">​</a></h1><div style="text-align:center;margin-bottom:2rem;"><h2 id="全端軟體工程師的技術工具箱" tabindex="-1">全端軟體工程師的技術工具箱 <a class="header-anchor" href="#全端軟體工程師的技術工具箱" aria-label="Permalink to “全端軟體工程師的技術工具箱”">​</a></h2><p>從 Delphi 桌面應用到 Golang + Vue.js 現代化 Web 應用，跨越前後端的全棧開發能力。</p></div><hr><h2 id="後端開發" tabindex="-1">後端開發 <a class="header-anchor" href="#後端開發" aria-label="Permalink to “後端開發”">​</a></h2><h3 id="go-golang" tabindex="-1">Go (Golang) <a class="header-anchor" href="#go-golang" aria-label="Permalink to “Go (Golang)”">​</a></h3><p>主要使用的後端程式語言，在工作中大量使用 Golang 進行 ERP 系統的 Web 化重構。</p><ul><li><strong>版本</strong>：Go 1.26.0</li><li><strong>框架</strong>：[Echo](<a href="https://echo" target="_blank" rel="noreferrer">https://echo</a> LAB.com/) v5.0.4 — 高效能 HTTP 框架</li><li><strong>ORM</strong>：<a href="https://xorm.io/" target="_blank" rel="noreferrer">XORM</a> v1.3.11 — 物件關聯對應工具</li><li><strong>應用場景</strong>： <ul><li>營建工程管理 ERP 系統後端 API</li><li>RESTful API 設計與開發</li><li>資料庫操作與管理</li><li>系統架構設計與重構</li></ul></li></ul><h3 id="主要技術棧" tabindex="-1">主要技術棧 <a class="header-anchor" href="#主要技術棧" aria-label="Permalink to “主要技術棧”">​</a></h3><table tabindex="0"><thead><tr><th>技術</th><th>類型</th><th>備註</th></tr></thead><tbody><tr><td>Go (Golang)</td><td>語言</td><td>主力後端語言</td></tr><tr><td>Echo</td><td>Web 框架</td><td>高效能 HTTP 框架</td></tr><tr><td>XORM</td><td>ORM</td><td>資料庫映射工具</td></tr><tr><td>RESTful API</td><td>架構風格</td><td>API 設計原則</td></tr><tr><td>Delphi 2009</td><td>語言</td><td>舊系統維護</td></tr></tbody></table><hr><h2 id="前端開發" tabindex="-1">前端開發 <a class="header-anchor" href="#前端開發" aria-label="Permalink to “前端開發”">​</a></h2><h3 id="vue-js-生態系統" tabindex="-1">Vue.js 生態系統 <a class="header-anchor" href="#vue-js-生態系統" aria-label="Permalink to “Vue.js 生態系統”">​</a></h3><p>現代化前端開發以 Vue.js 為核心，搭配多個工具與框架。</p><ul><li><strong>框架</strong>：Vue.js v3.5.29（Composition API）</li><li><strong>建構工具</strong>：Vite v7.2.6</li><li><strong>UI 框架</strong>： <ul><li><a href="https://primevue.org/" target="_blank" rel="noreferrer">PrimeVue</a> v4.5.4 — 豐富的 UI 元件庫</li><li><a href="https://tailwindcss.com/" target="_blank" rel="noreferrer">TailwindCSS</a> v4.1.18 — Utility-first CSS 框架</li><li><a href="https://master.co/" target="_blank" rel="noreferrer">MasterCSS</a> v1.37.8 — 語法驅動的 CSS 框架</li></ul></li><li><strong>HTTP 客戶端</strong>：Axios v1.13.5</li></ul><h3 id="主要技術棧-1" tabindex="-1">主要技術棧 <a class="header-anchor" href="#主要技術棧-1" aria-label="Permalink to “主要技術棧”">​</a></h3><table tabindex="0"><thead><tr><th>技術</th><th>類型</th><th>備註</th></tr></thead><tbody><tr><td>Vue.js</td><td>前端框架</td><td>v3.5.29，Composition API</td></tr><tr><td>Vite</td><td>建構工具</td><td>v7.2.6，快速熱重載</td></tr><tr><td>PrimeVue</td><td>UI 元件庫</td><td>v4.5.4</td></tr><tr><td>TailwindCSS</td><td>CSS 框架</td><td>v4.1.18</td></tr><tr><td>MasterCSS</td><td>CSS 框架</td><td>v1.37.8</td></tr><tr><td>Axios</td><td>HTTP 客戶端</td><td>v1.13.5</td></tr><tr><td>TypeScript</td><td>型別系統</td><td>靜態型別檢查</td></tr></tbody></table><hr><h2 id="桌面應用" tabindex="-1">桌面應用 <a class="header-anchor" href="#桌面應用" aria-label="Permalink to “桌面應用”">​</a></h2><h3 id="delphi-object-pascal" tabindex="-1">Delphi / Object Pascal <a class="header-anchor" href="#delphi-object-pascal" aria-label="Permalink to “Delphi / Object Pascal”">​</a></h3><p>在中程資訊顧問有限公司 (CMIS) 負責維護及開發 Delphi 2009 桌面應用程式。</p><ul><li><strong>應用系統</strong>： <ul><li>CMIS 整合桌面資訊系統</li><li>CMIS 銷售前置分析系統</li></ul></li><li><strong>經驗</strong>：從 Delphi 2009 開發的舊系統逐步重寫為 Web 版本</li></ul><hr><h2 id="系統運維" tabindex="-1">系統運維 <a class="header-anchor" href="#系統運維" aria-label="Permalink to “系統運維”">​</a></h2><h3 id="網路與伺服器" tabindex="-1">網路與伺服器 <a class="header-anchor" href="#網路與伺服器" aria-label="Permalink to “網路與伺服器”">​</a></h3><ul><li><strong>Minecraft 伺服器架設與管理</strong>：自 2013 年起從事伺服器架設，從 Minecraft 1.5.2 到多版本支援</li><li><strong>Windows 系統維護</strong>：系統重灌、電腦組裝、優化與故障排除</li><li><strong>網路設定</strong>：光纖網路升級、伺服器網路架構</li></ul><h3 id="其他技能" tabindex="-1">其他技能 <a class="header-anchor" href="#其他技能" aria-label="Permalink to “其他技能”">​</a></h3><ul><li>電腦硬體組裝與優化</li><li>系統重灌與維護</li><li>網路故障排除</li><li>Windows API 整合（Go winres）</li><li>開源套件維護（NPM packages）</li></ul>`,27)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};